export class ItensIngles {
    id: string;
    nome: string;
    tipo: string;
    preco: number;
    peso: number;
    raridade: string;
    sintonizavel: boolean;
    descricao: string;

    constructor(
        nome: string,
        tipo: string,
        preco: number,
        peso: number,
        raridade: string,
        sintonizavel: boolean,
        descricao: string
    ) {
        this.id = this.gerarIdUnico();
        this.nome = nome;
        this.tipo = tipo;
        this.peso = peso;
        this.preco = preco;
        this.raridade = raridade;
        this.sintonizavel = sintonizavel;
        this.descricao = descricao;
    }

    gerarIdUnico() {
        const timestamp = Date.now().toString(36);
        const random = Math.random().toString(36).substring(2, 5);
        return `${timestamp}-${random}`;
    };
}

